"""
MKT Christ in Every Verse — Romans chapters 4–7
Run: python3 scripts/zc-christ-romans-4-7.py

Source data used:
- data/translation/draft/mediating/romans.json (MKT text for quotation)
- data/commentary/mkt-christ/romans.json (ch.1-3 read for style/terminology continuity)
- data/interlinear/romans.json

Key decisions in this range:
- 5:14 "type of the one to come" — Paul's own term (typos); the Adam/Christ typology
  is not the interpreter's imposition but the text's own explicit category.
- 4:17b-21 — Abraham's faith in the resurrection-God is the same structural faith
  as faith in Christ's resurrection (4:24); the directness level is "type" since
  Paul explicitly identifies the connection.
- 7:4 "put to death to the law through the body of Christ" — a direct statement
  of Christ's atoning work as the means of covenant-transition; classified direct.
- The conflict of Romans 7 (whether describing unregenerate or regenerate experience
  is debated) — commentary focuses on the Christological resolution (7:25) rather
  than adjudicating the identity of the "I," since the resolution is unambiguous.
- Continuity from ch.1-3 style: directness level stated as "A direct:", "A type:",
  "A shadow:", "A theme:", "A revelation of God:"; MKT text quoted in italics.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "4": {
    "1": '<p>A theme: Paul begins the Abraham chapter with "What shall we say that Abraham, our forefather according to the flesh, discovered?" The question frames Abraham as a test case for the principle just announced (3:28). Abraham is the OT exemplar of the very faith-righteousness that the gospel declares; his story is not background color but the first-covenant proof of the Christ-principle.</p>',
    "2": '<p>A theme: "If, in fact, Abraham was justified by works, he had something to boast about — but not before God." The exclusion of boasting before God is the negative condition that reveals the structure of justification: it must be received, not earned, which is why Christ\'s righteousness rather than human achievement is the ground.</p>',
    "3": '<p>A direct: "Abraham believed God, and it was credited to him as righteousness" (Gen 15:6). This is the Scripture Paul presents as the backbone of his argument. The faith that was reckoned as righteousness anticipated the faith-in-the-risen-Christ of 4:24 — Abraham\'s trust in the God who calls the dead to life is the same structural act as trusting in the one who raised Jesus from the dead.</p>',
    "4": '<p>A theme: "Now to the one who works, wages are not credited as a gift but as an obligation." The wages-versus-gift contrast exposes the logic of all self-achievement religion: it produces debt-credits, not grace. Christ\'s righteousness given freely (3:24, <em>dōrean</em>) is structurally incapable of arising from the works-and-wages framework.</p>',
    "5": '<p>A direct: "However, to the one who does not work but trusts God who justifies the ungodly, their faith is credited as righteousness." The phrase "God who justifies the ungodly" is the theological center of Paul\'s Christology in miniature: God does not justify the qualified but the ungodly, which required the atoning work of 3:24-26 to make possible. This verse states the gospel\'s scandalous logic.</p>',
    "6": '<p>A type: David\'s blessing of the person whose sin is covered and to whom God does not credit iniquity (Ps 32:1-2) is another OT witness to the same principle as Abraham\'s reckoning. The person blessed in Ps 32 has no merit of their own — the blessing is the covering of sin. This is the type that Christ\'s atoning work fulfills.</p>',
    "7": '<p>A type: "Blessed are those whose transgressions are forgiven, whose sins are covered." The Psalm\'s blessing rests on divine action (forgiving, covering), not human performance. The gospel announces the ground on which God can legitimately cover sin: Christ bearing what the sinner deserved (3:25-26).</p>',
    "8": '<p>A type: "Blessed is the one whose sin the Lord will never count against them." The double negative (<em>ou mē logisetai</em>) is emphatic: the Lord will absolutely not credit this person\'s sin. The basis for this non-counting is left implicit in the Psalm; Paul\'s argument is that Christ\'s atoning death is what makes the non-imputation legally warranted rather than mere benign neglect.</p>',
    "9": '<p>A theme: Paul asks whether this blessedness comes to the circumcised or also to the uncircumcised. The question sets up the argument that Abraham\'s faith-righteousness preceded his circumcision, establishing the faith-principle as prior to and independent of the covenant-sign. This positions Christ\'s benefits as available apart from ethnic membership.</p>',
    "10": '<p>A theme: "It was not after, but before he was circumcised." The temporal sequence is the point: faith-righteousness came first, circumcision second. This temporal precedence is the structural argument for the priority of faith over sign in the order of salvation — which grounds the inclusion of Gentile believers in Abraham\'s spiritual offspring.</p>',
    "11": '<p>A type: Abraham received circumcision as a seal of the righteousness he already had through faith, making him the father of all who believe without being circumcised. The seal (circumcision) confirms rather than confers the faith-righteousness. Christ\'s death and resurrection are similarly confirmatory and constitutive of a righteousness received by faith, not generated by rite.</p>',
    "12": '<p>A theme: Abraham is father of the circumcised who also walk in his footsteps of faith. The double qualification insists that the sign without the faith is insufficient; the faith without the sign is sufficient. This establishes the principle that Gentile believers are Abraham\'s children not despite lacking circumcision but because they share his faith-structure.</p>',
    "13": '<p>A direct: "It was not through the law that Abraham and his offspring received the promise that he would be heir of the world, but through the righteousness that comes by faith." The world-inheritance promise (Ps 2:8; Gen 17:6) is given to Christ as the true seed (Gal 3:16) and to those in him. The "heir of the world" language anticipates the universal scope of Christ\'s kingdom.</p>',
    "14": '<p>A theme: "If those who depend on the law are heirs, faith means nothing and the promise is worthless." The argument by reductio establishes that the promise-structure is incompatible with a law-compliance structure; a promise by definition cannot be fulfilled by the recipient\'s own performance. Christ\'s fulfillment of the law on behalf of others is what keeps the promise intact.</p>',
    "15": '<p>A theme: "The law brings wrath" — because where there is law, transgression becomes defined and punishable. The law\'s function as wrath-generator points toward the need for a solution outside the law; Christ absorbing the wrath the law pronounces (3:25; 8:3) is the only resolution to this dynamic.</p>',
    "16": '<p>A direct: "Therefore, the promise comes by faith, so that it may be by grace and may be guaranteed to all Abraham\'s offspring — not only to those who are of the law but also to those who have the faith of Abraham." Grace guarantees what law cannot, because law conditions on human performance while grace rests on divine faithfulness. Christ is the guarantee of the new covenant (Heb 7:22) — the same logic Paul is establishing here.</p>',
    "17": '<p>A type: Abraham believed in "the God who gives life to the dead and calls into being things that were not." This characterization of God as the resurrection-God and the Creator-God ex nihilo is Paul\'s preparation for the following verses. Abraham\'s faith in this God structurally parallels faith in the God who raised Jesus; the resurrection is the defining act of the same God Abraham trusted.</p>',
    "18": '<p>A type: "Against all hope, Abraham in hope believed and so became the father of many nations." The faith-against-circumstance that characterizes Abraham is the OT pattern for all Christian faith — trusting in divine promise when natural conditions offer no ground for hope. The resurrection of Christ is the supreme case of the God who "gives life to the dead."</p>',
    "19": '<p>A type: Abraham "faced the fact that his body was as good as dead — since he was about a hundred years old — and that Sarah\'s womb was also dead." The bodily death that faith must overcome in Abraham (and Sarah) is the shadow of the physical death that Christ\'s resurrection overcomes; in both cases, new life comes not from biological resources but from divine creative power.</p>',
    "20": '<p>A type: Abraham "did not waver through unbelief regarding the promise of God, but was strengthened in his faith and gave glory to God." The persevering faith that gives glory to God rather than collapsing before impossible circumstances is the type of faith Paul will describe as the response to the resurrection announcement (v.24). Abraham\'s faith and resurrection-faith are the same structural act in different historical moments.</p>',
    "21": '<p>A type: Abraham was "fully persuaded that God had power to do what he had promised." The persuasion is about divine power, not human possibility; the faith attaches to God\'s capacity, not to visible evidence. This is precisely what Paul will say about resurrection-faith: it is trust in the power of the God who raised Jesus from the dead.</p>',
    "22": '<p>A direct: "This is why \'it was credited to him as righteousness.\'" The repetition of the Gen 15:6 citation from v.3 forms a bracket around the Abraham argument; his faith-righteousness is the model Paul has been expounding, and the model points beyond itself to the fulfillment in Christ.</p>',
    "23": '<p>A direct: "The words \'it was credited to him\' were written not for him alone." Paul\'s hermeneutical principle: the OT narrative was recorded for the sake of the new covenant community. Abraham\'s faith and its reckoning as righteousness is not a peculiarity of one man\'s biography but the disclosure of the principle by which God deals with all who trust him.</p>',
    "24": '<p>A direct: Faith is also credited to us "who believe in him who raised Jesus our Lord from the dead." The object of faith is now specified as the resurrection of Jesus, and the God who performed it. Abraham\'s faith and Christian faith share the same God and the same structure (trust in the life-giving God) now applied to the specific event of the resurrection.</p>',
    "25": '<p>A direct: "He was delivered over to death for our sins and was raised to life for our justification." The two-clause summary of the atonement and resurrection is one of the most compressed Christological statements in the NT. The delivery-for-sins corresponds to the sin-offering logic of 3:25; the raising-for-justification shows that the resurrection is not merely a miracle but the judicial declaration that the atoning sacrifice was accepted.</p>'
  },
  "5": {
    "1": '<p>A direct: "Therefore, since we have been justified through faith, we have peace with God through our Lord Jesus Christ." The peace is not a feeling but a covenantal status — the end of the enmity (cf. 8:7, the flesh hostile to God) achieved through the mediatorial work of Christ. Peace-with-God is the first-named consequence of the justification Paul has been establishing.</p>',
    "2": '<p>A direct: "We have gained access by faith into this grace in which we now stand." <em>Prosagōgē</em> (access) is a court-and-temple term: the right to come before the sovereign. Christ provides this access (Eph 2:18; 3:12) where the law could not. Boasting in hope of glory reverses the shame of 3:23 ("falling short of the glory of God") with eschatological confidence.</p>',
    "3": '<p>A theme: "We also glory in our sufferings, because we know that suffering produces perseverance." The paradox of finding ground for confidence in suffering rather than in achievement is the ethic of those who have been reconciled by Christ\'s death when they were enemies (v.10). The suffering-to-glory sequence parallels Christ\'s own path (8:17).</p>',
    "4": '<p>A theme: Perseverance produces character, and character hope. The virtuous sequence of v.3-4 is the outworking in the believer of what Christ\'s resurrection established: death does not have the final word; suffering is the seedbed of life. The hope it produces does not disappoint because it rests on the same God who raised Christ.</p>',
    "5": '<p>A direct: "God\'s love has been poured out into our hearts through the Holy Spirit, who has been given to us." The Spirit poured out is the fulfillment of Joel 2:28-29 and Ezek 36:26-27; the vehicle of this love is the Spirit given because of Christ\'s atoning work (cf. Gal 4:4-6). The love poured in is the experiential confirmation of the reconciliation announced in vv.1-2.</p>',
    "6": '<p>A direct: "You see, at just the right time, when we were still powerless, Christ died for the ungodly." The timing (<em>kairō</em> = the appointed time) grounds the cross in divine sovereign purpose, not contingency. The recipients — "powerless," "ungodly" — define the scandalous direction of Christ\'s self-giving: not toward the deserving but toward those with no claim whatsoever.</p>',
    "7": '<p>A direct: "Very rarely will anyone die for a righteous person, though for a good person someone might possibly dare to die." Paul argues by analogy from human experience: even the most heroic human death for the worthy is exceptional. Christ\'s death for enemies (v.10) and the ungodly (v.6) is of an entirely different category — which is why it reveals and demonstrates the love of God rather than merely human virtue.</p>',
    "8": '<p>A direct: "But God demonstrates his own love for us in this: while we were still sinners, Christ died for us." The demonstration (<em>synistēsin</em> = commends, proves by proof) is an objective act of God in history, not a feeling. The Christological claim is absolute: Christ\'s death is God\'s own self-demonstration of love — identifying Christ\'s act with God\'s own action.</p>',
    "9": '<p>A direct: "Since we have now been justified by his blood, how much more shall we be saved from God\'s wrath through him!" The <em>a fortiori</em> argument: if the more difficult thing (justification of sinners) has been accomplished, the less difficult (deliverance from wrath at the final judgment) is secure. The blood — the sacrificial offering language — is the basis of present justification and future deliverance.</p>',
    "10": '<p>A direct: "For if, while we were God\'s enemies, we were reconciled to him through the death of his Son, how much more, having been reconciled, shall we be saved through his life!" Reconciliation through Christ\'s death and salvation through his resurrected life are the two phases of the same redemption. The living Christ (not only the dying Christ) is Paul\'s ground of confidence for final salvation.</p>',
    "11": '<p>A direct: "We also boast in God through our Lord Jesus Christ, through whom we have now received reconciliation." The mediation is explicit: all access to God, all basis for confident relationship with God, comes through (<em>dia</em>) Jesus Christ. Boasting in God through Christ is the eschatological inversion of boasting in self-achievement.</p>',
    "12": '<p>A type: "Therefore, just as sin entered the world through one man, and death through sin, and in this way death came to all people, because all sinned..." The Adam-narrative begins. Paul\'s argument in vv.12-21 establishes Adam as the type whose action determined the condition of all who came after him — by analogy with and contrast to Christ, whose action determines the condition of all in him.</p>',
    "13": '<p>A theme: "To be sure, sin was in the world before the law was given, but sin is not charged against anyone\'s account where there is no law." The pre-law period demonstrates that death reigned independently of legal condemnation — which establishes that the death-problem is deeper than legal transgression and requires more than law-keeping to resolve.</p>',
    "14": '<p>A type: "Nevertheless, death reigned from the time of Adam to the time of Moses, even over those who did not sin by breaking a command, as did Adam, who is a <em>pattern</em> of the one to come." Paul explicitly names Adam as a type (<em>typos</em>) of Christ. The structural correspondence: one man\'s act determines the condition of all — in Adam, all die; in Christ, all (who are in him) are made alive. This is not a reader-imposed analogy; it is Paul\'s own typological argument.</p>',
    "15": '<p>A type: "But the gift is not like the trespass. For if the many died by the trespass of the one man, how much more did God\'s grace and the gift that came by the grace of the one man, Jesus Christ, overflow to the many!" The gift far exceeds the trespass in both quantity (<em>perisseuō</em> = overflow) and quality (grace versus condemnation). The type-and-antitype relationship is asymmetrical: Christ\'s act is infinitely more productive than Adam\'s was destructive.</p>',
    "16": '<p>A type: "Nor can the gift of God be compared with the result of one man\'s sin: The judgment followed one sin and brought condemnation, but the gift followed many trespasses and brought justification." The economy of divine grace inverts the economy of sin: one sin brought one condemnation; many sins brought one justification. The multiplication of sin does not outpace the gift.</p>',
    "17": '<p>A direct: "For if, by the trespass of the one man, death reigned through that one man, how much more will those who receive God\'s abundant provision of grace and of the gift of righteousness reign in life through the one man, Jesus Christ!" The reign of life through Christ explicitly answers the reign of death through Adam. The two-realm structure (death\'s reign vs. life\'s reign) is the Christological frame for the entire passage.</p>',
    "18": '<p>A direct: "Consequently, just as one trespass resulted in condemnation for all people, so also one righteous act resulted in justification and life for all people." The parallel is exact: one act, universal consequence. The "one righteous act" (<em>dikaiōma</em>) is Christ\'s atoning obedience, which Paul specifies in the next verse as his "obedience." This is the gospel\'s claim in its most compressed form.</p>',
    "19": '<p>A direct: "For just as through the disobedience of the one man the many were made sinners, so also through the obedience of the one man the many will be made righteous." The "obedience of Christ" is the active dimension of his life and death that accomplishes what Adam\'s disobedience undid. This is the basis of what later theology called Christ\'s active obedience — not merely dying for sin but living the perfect obedience that constitutes righteousness for all in him.</p>',
    "20": '<p>A theme: "The law was brought in so that the trespass might increase. But where sin increased, grace increased all the more." The law\'s role as sin-multiplier (by defining and therefore increasing transgression) is the penultimate word; grace\'s super-abundance is the final word. The law drives toward the need for grace; grace drives toward Christ who fulfills the law.</p>',
    "21": '<p>A direct: "So that, just as sin reigned in death, so also grace might reign through righteousness to bring eternal life through Jesus Christ our Lord." The final verse of the Adam/Christ argument closes the comparison: grace reigns through righteousness (Christ\'s own righteousness imputed and imparted), and its destination is eternal life — not death. The mediatorial phrase "through Jesus Christ our Lord" anchors the entire economy of grace in the specific person of the risen Lord.</p>'
  },
  "6": {
    "1": '<p>A theme: "What shall we say, then? Shall we go on sinning so that grace may increase?" The antinomian objection to grace is addressed. The question shows that Paul\'s gospel (ch.5 on grace\'s super-abundance) is radical enough to attract the charge of moral permissiveness — which confirms the depth of grace\'s unconditionality. His answer (vv.2-14) is grounded entirely in union with Christ, not in moral obligation as such.</p>',
    "2": '<p>A direct: "By no means! We are those who have died to sin; how can we live in it any longer?" Death-to-sin is not aspirational language but a description of a status change that occurred in union with Christ\'s death. The rhetorical force is: if you died to sin in Christ, continuing to live in it is ontologically impossible, not merely morally inadvisable.</p>',
    "3": '<p>A direct: "Or don\'t you know that all of us who were baptized into Christ Jesus were baptized into his death?" Baptism as union with Christ\'s death establishes the basis of vv.2 and 4. The death Paul is invoking is not metaphorical: it is participation in the historical death of Jesus, appropriated through faith and symbolized in baptism. The believer\'s identity is now defined by Christ\'s death.</p>',
    "4": '<p>A direct: "We were therefore buried with him through baptism into death in order that, just as Christ was raised from the dead through the glory of the Father, we too may live a new life." The resurrection of Christ is not merely the believer\'s future hope but the pattern and power of present new life. The logic of ch.4\'s resurrection-God is applied here: the God who raised Christ works in believers the same new-creation power.</p>',
    "5": '<p>A direct: "For if we have been united with him in a death like his, we will certainly also be united with him in a resurrection like his." The Greek <em>symphytos</em> (G4854, united with/grown together) is a biological term for organisms that have been grafted together; the union is organic, not merely legal. The certainty of the future resurrection grounds the present death-to-sin.</p>',
    "6": '<p>A direct: "For we know that our old self was crucified with him so that the body ruled by sin might be done away with, that we should no longer be slaves to sin." The "old self" (<em>palaios anthrōpos</em>) is the Adamic identity; its crucifixion with Christ is the decisive end of the sin-dominion established in ch.5. This is not progressive sanctification but a definitive event accomplished in Christ\'s death.</p>',
    "7": '<p>A theme: "Because anyone who has died has been set free from sin." The axiom: death terminates the claims of a prior domain. As a deceased person cannot be claimed by their former employer, so the one who has died with Christ is released from sin\'s legal hold. The resurrection of Christ confirms that the release from sin\'s dominion is permanent.</p>',
    "8": '<p>A direct: "Now if we died with Christ, we believe that we will also live with him." The co-death establishes the co-life; they cannot be separated. The future "will live with him" encompasses both the present spiritual life and the future bodily resurrection, both grounded in the same union with Christ.</p>',
    "9": '<p>A direct: "For we know that since Christ was raised from the dead, he cannot die again; death no longer has mastery over him." Christ\'s resurrection is permanent and unrepeatable: death\'s dominion over him is definitively ended. The resurrection is not resuscitation (return to the previous life) but transformation into a mode of existence no longer subject to death.</p>',
    "10": '<p>A direct: "The death he died, he died to sin once for all; but the life he lives, he lives to God." The adverb <em>ephapax</em> (once for all, G2178) marks the unrepeatable character of Christ\'s death to sin; its once-for-all nature is the ground for its universal sufficiency. The life he now lives is wholly oriented toward God — which is the pattern for the believer\'s own ethical life (v.11).</p>',
    "11": '<p>A direct: "In the same way, count yourselves dead to sin but alive to God in Christ Jesus." The imperative <em>logizesthe</em> (count/reckon, the imputation-verb from ch.4) is applied here to personal identity: believers are to reckon their death and life according to their union with Christ rather than according to sin\'s claim. The status is established; the reckoning brings behavior into conformity with reality.</p>',
    "12": '<p>A theme: "Therefore do not let sin reign in your mortal body so that you obey its evil desires." The exhortation follows from the indicative (vv.6-11); sin\'s reign has been broken in principle, and the practical realization of that break is the ethical task. "Mortal body" holds the tension: the body is still mortal (not yet resurrected) but need not be sin\'s instrument.</p>',
    "13": '<p>A direct: "Do not offer any part of yourself to sin as an instrument of wickedness, but rather offer yourselves to God as those who have been brought from death to life." The phrase "brought from death to life" is resurrection language applied to present existence; the transfer from death-domain to life-domain has occurred (v.4), and the ethical consequence is to present oneself to God in keeping with that transfer.</p>',
    "14": '<p>A direct: "For sin shall no longer be your master, because you are not under the law, but under grace." The <em>kur-</em> (master) language: sin\'s dominion is ended not by effort but by a change of covenant domain. Being under grace rather than law means standing in the sphere of Christ\'s accomplished work; sin\'s claim has no legal standing in that domain.</p>',
    "15": '<p>A theme: "What then? Shall we sin because we are not under the law but under grace?" The second antinomian objection is similar to the first (v.1) but focuses on grace\'s freedom from law rather than grace\'s super-abundance. The grace Paul preaches is radical enough that misunderstanding it as license is understandable — which is evidence of the gospel\'s genuine unconditionality.</p>',
    "16": '<p>A theme: "Don\'t you know that when you offer yourselves to someone as obedient slaves, you are slaves of the one you obey — whether you are slaves to sin, which leads to death, or to obedience, which leads to righteousness?" The slave-and-master binary replaces the law-and-grace binary of the previous argument; total allegiance to one master is the condition of the human will, and the transfer from sin\'s ownership to Christ\'s is the gospel\'s accomplishment.</p>',
    "17": '<p>A direct: "Thanks be to God that, though you used to be slaves to sin, you have come to obey from your heart the pattern of teaching that has now claimed your allegiance." The thanks is to God because the transfer of allegiance was God\'s act, not the believer\'s. "Pattern of teaching" (<em>typos didachēs</em>) is the apostolic deposit about Christ that reshapes the whole person.</p>',
    "18": '<p>A direct: "You have been set free from sin and have become slaves to righteousness." The passive <em>eleutherōthentes</em> (you were freed) indicates divine action; the active <em>edoulōthēte</em> (you became enslaved) indicates the resulting new allegiance. Freedom from sin and slavery to righteousness are the two sides of the same liberation that Christ\'s atoning death accomplished.</p>',
    "19": '<p>A theme: Paul uses human analogies about slavery "because of your human limitations." The apology for the metaphor recognizes its limitations; what he is describing (the complete reorientation of the will through Christ\'s work) is larger than any human analogy can contain. The direction is clear: toward holiness, which is the goal of the union with Christ Paul has been describing.</p>',
    "20": '<p>A theme: "When you were slaves to sin, you were free from the control of righteousness." The previous freedom from righteousness is exposed as slavery; what looked like liberty was servitude. Christ\'s liberation reverses this: freedom from sin produces willing slavery to the one whose service is perfect freedom.</p>',
    "21": '<p>A theme: "What benefit did you reap at that time from the things you are now ashamed of? Those things result in death!" The shame and death produced by the former life contrast with the holiness and eternal life of the new. The question exposes the bankruptcy of the old life by its own outcome — which is the argument by consequences that Paul uses to ground the new life in Christ.</p>',
    "22": '<p>A direct: "But now that you have been set free from sin and have become slaves of God, the benefit you reap leads to holiness, and the result is eternal life." The Christological logic: freedom from sin (Christ\'s atoning work) produces willing service to God (the Spirit\'s work) that leads to holiness (progressive) and eternal life (eschatological). The whole is Christ\'s doing, not the believer\'s achievement.</p>',
    "23": '<p>A direct: "For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord." The final verse of the chapter draws the absolute contrast. Sin operates on wages-logic: it pays out what is earned. God operates on gift-logic: eternal life is given, not earned. The gift is specifically located "in Christ Jesus our Lord" — not as a general divine benevolence but as the fruit of the specific person and work of the Lord Jesus.</p>'
  },
  "7": {
    "1": '<p>A theme: "Do you not know, brothers and sisters — for I am speaking to those who know the law — that the law has authority over someone only as long as that person lives?" Paul introduces the death-as-release principle using the analogy of law\'s temporal domain. The principle prepares for the decisive Christological statement of v.4: death with Christ releases from the law\'s claim.</p>',
    "2": '<p>A theme: The marriage-law analogy: a married woman is bound by law to her husband as long as he lives; his death frees her. The analogy will be applied in v.4, where the believer\'s death with Christ is what frees from the law. The point is the legitimate dissolution of one covenant bond by death, enabling a new union.</p>',
    "3": '<p>A theme: The adultery analogy: if she joins another man while her husband lives, she is an adulteress; if he dies, she is free to remarry without that designation. This establishes that the transition from law to grace is not infidelity to God but the legitimate consequence of death with Christ — the old covenant\'s claim ended through the believer\'s death in Christ, not through divorce.</p>',
    "4": '<p>A direct: "So, my brothers and sisters, you also died to the law through the body of Christ, that you might belong to another, to him who was raised from the dead, in order that we might bear fruit for God." The verse is the application of the analogy. "Through the body of Christ" specifies the mechanism: Christ\'s physical death is the death through which believers die to the law. The goal is belonging to Christ (marriage analogy completed) and bearing fruit — covenant life in the new union.</p>',
    "5": '<p>A theme: "For when we were in the realm of the flesh, the sinful passions aroused by the law were at work in us, so that we bore fruit for death." The contrast with v.4\'s fruit-for-God: the pre-Christ life produced fruit-for-death. The law paradoxically aroused sin rather than suppressing it (amplified in vv.7-25), which is why the solution requires Christ\'s work, not law-improvement.</p>',
    "6": '<p>A direct: "But now, by dying to what once bound us, we have been released from the law so that we serve in the new way of the Spirit, and not in the old way of the written code." The Spirit-versus-letter antithesis (cf. 2 Cor 3:6) frames the new covenant\'s character: not external compliance with a written code but the Spirit\'s inward renewal, which is the Jeremiah 31 promise now realized in Christ\'s gift of the Spirit (cf. 8:2).</p>',
    "7": '<p>A theme: "What shall we say, then? Is the law sinful? Certainly not! Nevertheless, I would not have known what sin was had it not been for the law." The law is declared holy (v.12) and its diagnostic function affirmed. The law\'s revelation of sin is not a defect but a feature; it is the mirror that shows the condition requiring the physician. Christ does not come despite the law but because of what the law reveals.</p>',
    "8": '<p>A theme: "But sin, seizing the opportunity afforded by the commandment, produced in me every kind of coveting. For apart from the law, sin was dead." The perverse dynamic: the prohibition activates the desire it prohibits. This is not the law\'s fault but sin\'s exploitation of the law\'s good function. It establishes the impossibility of self-improvement through law-intensification — only death-and-resurrection (ch.6) can break the cycle.</p>',
    "9": '<p>A theme: "Once I was alive apart from the law; but when the commandment came, sin sprang to life and I died." The narrative of pre-law innocence, law-arrival, sin-activation, and death is the individual analogue of the Adam narrative (cf. 5:12-14). The same pattern: innocence, commandment, transgression, death. Christ\'s reversal of Adam\'s path is the only resolution to this structural repetition.</p>',
    "10": '<p>A theme: "I found that the very commandment that was intended to bring life actually brought death." The commandment\'s double face: designed for life (Lev 18:5), producing death through sin\'s exploitation. This is why the law cannot be the gospel — not because it is bad but because it is unable to deal with the sin that subverts it. Only a power stronger than sin\'s exploitation of the law can bring the life the law promised.</p>',
    "11": '<p>A theme: "For sin, seizing the opportunity afforded by the commandment, deceived me, and through the commandment put me to death." The language of deception echoes Gen 3:13 (the serpent\'s deception); sin plays the serpent\'s role, using the commandment as the occasion for its deceptive work. The pattern from Eden repeats in every human encounter with the law.</p>',
    "12": '<p>A revelation of God: "So then, the law is holy, and the commandment is holy, righteous and good." Paul\'s vindication of the Torah: its holiness, righteousness, and goodness are non-negotiable attributes. The law\'s failure to produce life is not a defect in the law but a disclosure of the depth of the sin-problem. God\'s law reflects God\'s holy character; Christ does not abolish but fulfills it (8:4).</p>',
    "13": '<p>A theme: "Did that which is good, then, become death to me? By no means! Nevertheless, in order that sin might be recognized as sin, it used what is good to bring about my death, so that through the commandment sin might become utterly sinful." The law\'s revealing function: it makes sin visibly "utterly sinful" by the contrast between the holy commandment and sin\'s willful transgression of it. This revelation of sin\'s depth points toward the necessity of an atoning solution rather than a corrective one.</p>',
    "14": '<p>A theme: "We know that the law is spiritual; but I am unspiritual, sold as a slave to sin." The contrast: law-as-spiritual vs. self-as-unspiritual. The incompatibility between the spiritual law and the unspiritual self is the human predicament that neither willpower nor law-intensification can resolve. The only resolution is the Spirit who fulfills the law\'s righteous requirement in believers (8:4).</p>',
    "15": '<p>A theme: "I do not understand what I do. For what I want to do I do not do, but what I hate I do." The conflict described in vv.15-23 reveals the profound disintegration of the will under sin\'s dominion. Whatever the "I" refers to (regenerate or unregenerate experience is debated), the predicament discloses the impossibility of self-redemption: the will itself is split, wanting the good it cannot achieve.</p>',
    "16": '<p>A revelation of God: "And if I do what I do not want to do, I agree that the law is good." The inner conflict itself witnesses to the law\'s goodness: the part of the person that wants to do the right thing is confirming the law\'s justice. The law\'s goodness is not nullified by the inability to keep it; that inability drives toward Christ.</p>',
    "17": '<p>A theme: "As it is, it is no longer I myself who do it, but it is sin living in me." The distinction between the person and the sin-power dwelling in them is not an escape from responsibility but a diagnostic: sin is a power that has taken up residence in the person, not merely a list of bad choices. What is needed is an exorcism of sin from its habitation, which only Christ\'s death and the Spirit\'s indwelling can accomplish.</p>',
    "18": '<p>A theme: "For I know that good itself does not dwell in me, that is, in my sinful nature. For I have the desire to do what is good, but I cannot carry it out." The limits of good intentions without transformative power: the desire is present, the capacity absent. This is the gap that Christ\'s work bridges: not by strengthening the will but by dealing with the sin that makes the will ineffective (6:6-7; 8:3-4).</p>',
    "19": '<p>A theme: "For I do not do the good I want to do, but the evil I do not want to do — this I keep on doing." The repetition of the same conflict (cf. v.15) emphasizes the persistence of the predicament and the inability of insight or intention to resolve it. The resolution must come from outside the self entirely.</p>',
    "20": '<p>A theme: "Now if I do what I do not want to do, it is no longer I who do it, but it is sin living in me that does it." The repeated formulation underlines the alien-power quality of sin; the person who wants the good is not the same as the agent producing the evil, though they are the same person. This is the depth of sin\'s colonization of the human person that makes rescue rather than reform the necessary response.</p>',
    "21": '<p>A theme: "So I find this law at work: Although I want to do good, evil is right there with me." The "law" here is not the Mosaic law but the empirical principle of habitual evil co-present with the intention to do good. The structural entanglement of good intention and evil performance is the natural condition that Christ\'s atoning work addresses at the level of co-crucifixion with the old self (6:6).</p>',
    "22": '<p>A revelation of God: "For in my inner being I delight in God\'s law." Whatever the identity of the "I" in this chapter, the delight in God\'s law in the inner person is significant: the law itself is not the enemy. The conflict is between the person who wants to honor the law and the sin-power that prevents it. Christ fulfills the law\'s righteous requirement (8:4) precisely because no fallen person can do so from within the old Adam.</p>',
    "23": '<p>A theme: "But I see another law at work in me, waging war against the law of my mind and making me a prisoner of the law of sin at work within me." The warfare metaphor: sin wages active campaign against the renewed mind\'s intention. The captivity Paul describes is the condition from which Christ\'s rescue (v.24-25) delivers; it is not the permanent condition of the believer but the vivid description of what awaits without him.</p>',
    "24": '<p>A direct: "What a wretched man I am! Who will rescue me from this body that is subject to death?" The cry for rescue (<em>rysesthai</em> = deliver, rescue) is addressed to a liberator outside the self; it cannot be self-rescue. The question "who will?" anticipates the answer in v.25, which names the deliverer rather than a program or technique. The cry establishes the soteriological logic: the problem is one that only a person can resolve, which is why the gospel is centered on a person.</p>',
    "25": '<p>A direct: "Thanks be to God, who delivers me through Jesus Christ our Lord!" The exclamation of rescue answers the cry of v.24. The deliverer is named: Jesus Christ our Lord. The Christological specificity is the answer to the existential cry — not a principle, not a technique, not a moral program, but a person through whom God delivers the one who cries out. The mediation is explicit: "through Jesus Christ," not through human effort reshaped by Christ\'s teaching, but through the person of the mediator himself.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-christ', 'romans', existing)
    print('Romans 4–7 mkt-christ written.')

if __name__ == '__main__':
    main()
